    final placeholders = values.keys.map((_) => '?').join(', ');
    execute('INSERT INTO $table ($columns) VALUES ($placeholders)', values.values.toList());
  }

  int update(String table, Map<String, dynamic> values, {String? where, List<Object?>? whereArgs}) {
    final setClause = values.keys.map((k) => '$k = ?').join(', ');
    final allArgs = [...values.values, ...?whereArgs];
    final sql = 'UPDATE $table SET $setClause${where != null ? ' WHERE $where' : ''}';
    execute(sql, allArgs);
    return 0; // sqlite3 doesn't expose row count via a property
  }

  int delete(String table, {String? where, List<Object?>? whereArgs}) {
    final sql = 'DELETE FROM $table${where != null ? ' WHERE $where' : ''}';
    execute(sql, whereArgs ?? []);
    return 0; // sqlite3 doesn't expose row count via a property
  }
}

