class ReadingGoal {
  final String id;
  final int year;
  final int? month;
  final String type; // 'books', 'pages', 'minutes'
  final int target;
  final int progress;

  ReadingGoal({
    required this.id,
    required this.year,
    this.month,
    required this.type,
    required this.target,
    this.progress = 0,
  });

  double get percentage => target > 0 ? (progress / target).clamp(0.0, 1.0) : 0.0;
  bool get isComplete => progress >= target;
  int get remaining => (target - progress).clamp(0, target);

