  int currentStreak() {
    final rows = _db.select('''
      SELECT DISTINCT DATE(end_time) as read_date 
      FROM reading_sessions 
      WHERE end_time IS NOT NULL 
      ORDER BY read_date DESC
    ''');

    if (rows.isEmpty) return 0;

    final dates = rows.map((r) => r['read_date'] as String).toList();
    final today = DateTime.now();
    final todayStr = '${today.year}-${today.month.toString().padLeft(2, '0')}-${today.day.toString().padLeft(2, '0')}';
    final yesterday = today.subtract(const Duration(days: 1));
    final yesterdayStr = '${yesterday.year}-${yesterday.month.toString().padLeft(2, '0')}-${yesterday.day.toString().padLeft(2, '0')}';

    if (dates.first != todayStr && dates.first != yesterdayStr) return 0;

    int streak = 0;
    final allDates = dates.map((d) => DateTime.parse(d)).toList();
    for (int i = 0; i < allDates.length; i++) {
      if (i == 0) {
        streak = 1;
        continue;
      }
      final diff = allDates[i - 1].difference(allDates[i]).inDays;
      if (diff == 1) {
        streak++;
      } else {
        break;
      }
    }
    return streak;
  }

  Map<int, int> monthlyPages(int year) {
    final result = <int, int>{};
    for (int m = 1; m <= 12; m++) result[m] = 0;

    final rows = _db.select('''
      SELECT CAST(strftime('%m', start_time) AS INTEGER) as month,
             COALESCE(SUM(pages_read), 0) as total
      FROM reading_sessions
      WHERE pages_read IS NOT NULL
        AND CAST(strftime('%Y', start_time) AS INTEGER) = ?
      GROUP BY month
      ORDER BY month
    ''', [year]);

    for (final row in rows) {
      result[row['month'] as int] = (row['total'] as num).toInt();
    }
    return result;
  }

  Map<int, int> monthlyDuration(int year) {
    final result = <int, int>{};
    for (int m = 1; m <= 12; m++) result[m] = 0;

    final rows = _db.select('''
      SELECT CAST(strftime('%m', start_time) AS INTEGER) as month,
             COALESCE(SUM(duration_seconds), 0) as total
      FROM reading_sessions
      WHERE duration_seconds IS NOT NULL
        AND CAST(strftime('%Y', start_time) AS INTEGER) = ?
      GROUP BY month
      ORDER BY month
    ''', [year]);

    for (final row in rows) {
      result[row['month'] as int] = (row['total'] as num).toInt();
    }
    return result;
  }

  Map<String, int> topGenres({int limit = 5}) {
    final books = getBooksByStatus(ReadingStatus.finished);
    final genreCount = <String, int>{};
    for (final book in books) {
      for (final cat in book.categories) {
        genreCount[cat] = (genreCount[cat] ?? 0) + 1;
      }
    }
    final sorted = genreCount.entries.toList()
      ..sort((a, b) => b.value.compareTo(a.value));
    return Map.fromEntries(sorted.take(limit));
  }

  List<Book> recentlyRead({int limit = 10}) {
    final rowIds = _db.select('''
      SELECT DISTINCT book_id FROM reading_sessions 
      WHERE end_time IS NOT NULL 
      ORDER BY end_time DESC 
      LIMIT ?
    ''', [limit]);

    final books = <Book>[];
    for (final row in rowIds) {
      final book = getBook(row['book_id'] as String);
      if (book != null) books.add(book);
    }
    return books;
  }

  /// Migration helper: adds title/author/cover_url columns to existing recommendations table.
  void _migrateRecommendationsTable() {
    for (final col in ['title', 'author', 'cover_url']) {
      try {
        _db.execute('ALTER TABLE recommendations ADD COLUMN $col TEXT');
      } catch (_) {
        // Column already exists — ignore
      }
    }
  }

  void close() {
    _db.dispose();
    _instance = null;
  }
